import { readFileSync } from 'node:fs';
import { resolve } from 'node:path';

import { describe, expect, it } from 'vitest';

// `src/bin/openai-server.ts` calls main() unconditionally at module scope (no
// entrypoint guard), so it cannot be safely `import`-ed in a test — the
// established convention here (see openai-server-thoth-oath-config.test.ts)
// is source-string presence assertions. Real correctness of the wire formats
// themselves (exact tags, parsing, round-trip shapes) is covered by the
// genuinely-importable, fully unit-tested native-tool-formats.test.ts; this
// file only confirms the openai-server-side glue that wires that module in.
const serverSource = readFileSync(
  resolve(__dirname, '../src/bin/openai-server.ts'),
  'utf8',
);

describe('openai-server native tool-calling wiring', () => {
  it('gates native tool-calling behind MOONSHINE_NATIVE_TOOL_CALLING (default on) and Gemma4 behind a separate experimental flag', () => {
    expect(serverSource).toContain("process.env['MOONSHINE_NATIVE_TOOL_CALLING'] !== '0'");
    expect(serverSource).toContain("process.env['GEMMA4_NATIVE_TOOLS_EXPERIMENTAL'] === '1'");
  });

  it('resolves nativeToolFamily once per runtime and exposes it on the AgenticChatRuntime', () => {
    expect(serverSource).toContain('resolveNativeToolFamily(chatTemplate');
    expect(serverSource).toContain('nativeToolFamily,');
  });

  it('widens Message with optional tool_calls/tool_call_id/name fields', () => {
    expect(serverSource).toContain('tool_calls?: AgenticToolCall[]');
    expect(serverSource).toContain('tool_call_id?: string');
  });

  it('allows role:"tool" through the family renderer only for native-tool chat templates', () => {
    expect(serverSource).toContain('function isNativeToolChatTemplate(chatTemplate: ChatTemplate)');
    expect(serverSource).toContain('function canUseFamilyChatTemplate(');
    expect(serverSource).toContain("allowToolRole && message.role === 'tool'");
  });

  it('applyQwenChatTemplate renders tool results and assistant tool_calls in native shape', () => {
    expect(serverSource).toContain("if (msg.role === 'tool') {");
    expect(serverSource).toContain('formatQwenToolResultTurn(msg.content)');
    expect(serverSource).toContain('formatQwenAssistantToolCallTurn(msg.tool_calls)');
  });

  it('buildRuntime.infer no longer silently strips tool_calls/tool_call_id/name from prompt messages', () => {
    // Regression guard for the bug the design pass found: promptMessages used
    // to map only {role, content}, discarding tool_calls/tool_call_id/name —
    // meaning a native family could never see its own prior tool calls.
    expect(serverSource).toContain('const promptMessages: Message[] = request.messages.map((message) => ({');
    expect(serverSource).toMatch(/promptMessages[\s\S]{0,400}message\.tool_calls/);
  });

  it('allows role:"tool" through for mistral-v3-instruct too', () => {
    expect(serverSource).toContain("if (chatTemplate === 'mistral-v3-instruct') return true;");
  });

  it('threads tools through renderPromptForGeneration into applyMistralV3InstructTemplate', () => {
    expect(serverSource).toContain('tools?: AgenticToolDefinition[],');
    expect(serverSource).toContain('applyMistralV3InstructTemplate(messages.map(toRenderMessage), tools)');
  });

  it('delegates the actual Mistral rendering to the pure, unit-tested native-tool-formats module', () => {
    // The real logic (and its exact-string tests) live in
    // native-tool-formats.test.ts's `renderMistralV3InstructPrompt` suite —
    // this file must stay a thin, unconditionally-side-effecting wrapper.
    expect(serverSource).toContain('renderMistralV3InstructPrompt');
    expect(serverSource).toContain('return renderMistralV3InstructPrompt(messages, tools);');
  });

  it('gates Gemma4 role:"tool" access behind GEMMA4_NATIVE_TOOLS_EXPERIMENTAL specifically', () => {
    expect(serverSource).toContain(
      "if (chatTemplate === 'gemma4') return GEMMA4_NATIVE_TOOLS_EXPERIMENTAL;",
    );
  });

  it('applyGemma4ChatTemplate renders tool results and assistant tool_calls in the mini-DSL shape', () => {
    expect(serverSource).toContain('formatGemma4ToolResultTurn(msg.content, msg.name');
    expect(serverSource).toContain('formatGemma4ToolCallTurn(msg.tool_calls)');
  });

  it('does not enable Gemma4 native tools by default (experimental, opt-in only)', () => {
    expect(serverSource).toContain("process.env['GEMMA4_NATIVE_TOOLS_EXPERIMENTAL'] === '1'");
    // Confirms the flag is a strict-equality opt-in, not a default-on/kill-switch
    // like MOONSHINE_NATIVE_TOOL_CALLING — i.e. unset or any value other than
    // the literal string '1' keeps Gemma4 on the generic fenced-block path.
  });
});
